#!/bin/bash
exec > /var/log/userdata.log 2>&1
set -x

EXIT_CODE=0
send_signal() {
  /opt/aws/bin/cfn-signal \
    --exit-code "$EXIT_CODE" \
    --stack    "${StackName}" \
    --resource EC2Instance \
    --region   "${Region}"
}
trap 'EXIT_CODE=$?; send_signal' EXIT

yum update -y
amazon-linux-extras enable php8.2
yum clean metadata
yum install -y httpd php php-cli php-mysqlnd mysql aws-cfn-bootstrap \
    xrdp tigervnc-server xterm nginx openssl

# Fix SSH password authentication
# Must patch both sshd_config AND cloud-init's sshd config
# because cloud-init overrides sshd_config on Amazon Linux 2

# 1. Patch main sshd_config
sed -i 's/^PasswordAuthentication no/PasswordAuthentication yes/' /etc/ssh/sshd_config
sed -i 's/^#PasswordAuthentication yes/PasswordAuthentication yes/' /etc/ssh/sshd_config
grep -q '^PasswordAuthentication yes' /etc/ssh/sshd_config || echo 'PasswordAuthentication yes' >> /etc/ssh/sshd_config

# 2. Patch cloud-init sshd config - this is the one that overrides
# Amazon Linux 2 cloud-init writes its own sshd config that takes precedence
if [ -f /etc/ssh/sshd_config.d/50-cloud-init.conf ]; then
    sed -i 's/^PasswordAuthentication no/PasswordAuthentication yes/' /etc/ssh/sshd_config.d/50-cloud-init.conf
fi

# 3. Write our own override file - highest priority
mkdir -p /etc/ssh/sshd_config.d
cat > /etc/ssh/sshd_config.d/99-password-auth.conf << 'SSHEOF'
PasswordAuthentication yes
ChallengeResponseAuthentication no
UsePAM yes
SSHEOF
chmod 600 /etc/ssh/sshd_config.d/99-password-auth.conf

# 4. Restart sshd
systemctl restart sshd
echo "SSH password authentication enabled"

LINUX_USER="${LinuxUser}"
LINUX_PASS="${LinuxPass}"
useradd -m -s /bin/bash "$LINUX_USER"
echo "$LINUX_USER:$LINUX_PASS" | chpasswd
usermod -aG wheel "$LINUX_USER"
echo "$LINUX_USER ALL=(ALL) NOPASSWD:ALL" > /etc/sudoers.d/labuser
chmod 440 /etc/sudoers.d/labuser

cat > /home/$LINUX_USER/.xsession << 'XEOF'
exec xterm
XEOF
chown $LINUX_USER:$LINUX_USER /home/$LINUX_USER/.xsession
chmod 755 /home/$LINUX_USER/.xsession

systemctl start xrdp
systemctl enable xrdp

mkdir -p /etc/nginx/ssl
openssl req -x509 -nodes -days 3650 -newkey rsa:2048 \
  -keyout /etc/nginx/ssl/rdp.key \
  -out    /etc/nginx/ssl/rdp.crt \
  -subj   "/C=US/ST=Lab/L=Lab/O=CloudLabs/CN=cloudlabs-rdp"

cat > /etc/nginx/nginx.conf << 'NGINXEOF'
user nginx;
worker_processes auto;
error_log /var/log/nginx/error.log;
pid /run/nginx.pid;
events { worker_connections 1024; }
stream {
    upstream xrdp_backend { server 127.0.0.1:3389; }
    server {
        listen 443 ssl;
        ssl_certificate     /etc/nginx/ssl/rdp.crt;
        ssl_certificate_key /etc/nginx/ssl/rdp.key;
        ssl_protocols       TLSv1.2 TLSv1.3;
        proxy_pass          xrdp_backend;
        proxy_timeout       3600s;
        proxy_connect_timeout 10s;
    }
}
http {
    include      /etc/nginx/mime.types;
    default_type application/octet-stream;
    sendfile on;
    keepalive_timeout 65;
}
NGINXEOF

systemctl start nginx
systemctl enable nginx

systemctl start httpd
systemctl enable httpd
usermod -a -G apache ec2-user
chown -R ec2-user:apache /var/www
chmod 2775 /var/www
find /var/www -type d -exec chmod 2775 {} \;
find /var/www -type f -exec chmod 0664 {} \;

RDS_HOST="${RDSEndpoint}"
DB_NAME="${DBName}"
DB_USER="${DBUser}"
DB_PASS="${DBPass}"

cat > /var/www/html/db_config.php << PHPEOF
<?php
define('DB_HOST', '$RDS_HOST');
define('DB_NAME', '$DB_NAME');
define('DB_USER', '$DB_USER');
define('DB_PASS', '$DB_PASS');
?>
PHPEOF
chmod 640 /var/www/html/db_config.php

export MYSQL_PWD="$DB_PASS"
RDS_READY=0
echo "Waiting for RDS..."
for i in $(seq 1 40); do
  if mysql -h "$RDS_HOST" -u "$DB_USER" -e "SELECT 1;" "$DB_NAME" 2>/dev/null; then
    echo "RDS ready on attempt $i"
    RDS_READY=1
    break
  fi
  echo "Attempt $i/40 failed, retrying in 20s..."
  sleep 20
done

if [ "$RDS_READY" -eq 0 ]; then
  echo "ERROR: RDS never became reachable"
  exit 1
fi

mysql -h "$RDS_HOST" -u "$DB_USER" "$DB_NAME" << 'SQLEOF'
CREATE TABLE IF NOT EXISTS users (
  id         INT AUTO_INCREMENT PRIMARY KEY,
  name       VARCHAR(100) NOT NULL,
  address    VARCHAR(255) NOT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
SQLEOF

cat > /var/www/html/index.php << 'WEBEOF'
<?php
require_once 'db_config.php';
$conn = new mysqli(DB_HOST, DB_USER, DB_PASS, DB_NAME);
if ($conn->connect_error) {
    die('<p style="color:red"><strong>DB Connection Failed:</strong> ' . htmlspecialchars($conn->connect_error) . '</p>');
}
$conn->set_charset('utf8mb4');
if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $action = $_POST['action'] ?? '';
    if ($action === 'insert') {
        $name    = $conn->real_escape_string(trim($_POST['name']    ?? ''));
        $address = $conn->real_escape_string(trim($_POST['address'] ?? ''));
        if ($name !== '' && $address !== '') {
            $conn->query("INSERT INTO users (name, address) VALUES ('$name', '$address')");
        }
    }
    if ($action === 'delete') {
        $id = (int)($_POST['id'] ?? 0);
        if ($id > 0) { $conn->query("DELETE FROM users WHERE id = $id"); }
    }
    header('Location: /index.php');
    exit;
}
$result = $conn->query('SELECT * FROM users ORDER BY created_at DESC');
?>
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>CloudLabs Web App</title>
<style>
  body{font-family:Arial,sans-serif;max-width:760px;margin:40px auto;padding:0 20px;background:#f0f2f5}
  h1{color:#1a1a2e}
  .card{background:#fff;padding:24px;border-radius:10px;margin-bottom:28px;box-shadow:0 2px 8px rgba(0,0,0,.08)}
  label{font-weight:600;display:block;margin-bottom:4px;color:#333}
  input[type=text]{width:100%;padding:10px;margin-bottom:16px;border:1px solid #ccc;border-radius:6px;box-sizing:border-box;font-size:15px}
  .btn-save{background:#0077cc;color:#fff;padding:10px 28px;border:none;border-radius:6px;font-size:15px;cursor:pointer}
  .btn-save:hover{background:#005fa3}
  .btn-delete{background:#e53935;color:#fff;padding:5px 14px;border:none;border-radius:5px;font-size:13px;cursor:pointer}
  .btn-delete:hover{background:#b71c1c}
  table{width:100%;border-collapse:collapse}
  th,td{padding:10px 12px;text-align:left;border-bottom:1px solid #e0e0e0}
  th{background:#0077cc;color:#fff}
  tr:hover td{background:#f5f9ff}
  .tag{background:#d4edda;color:#155724;padding:2px 8px;border-radius:10px;font-size:.8em}
  .info{font-size:.9em;color:#555;margin-bottom:20px}
  .empty{color:#888;font-style:italic}
</style>
</head>
<body>
<h1>CloudLabs Web Application</h1>
<p class="info">Infrastructure: <strong>Amazon EC2</strong> (Apache + PHP 8.2) &rarr; <strong>Amazon RDS MySQL 8.0</strong></p>
<div class="card">
  <h2>Submit Your Details</h2>
  <form method="POST">
    <input type="hidden" name="action" value="insert">
    <label>Full Name</label>
    <input type="text" name="name" placeholder="Enter your name" required>
    <label>Address</label>
    <input type="text" name="address" placeholder="Enter your address" required>
    <button type="submit" class="btn-save">Save to Database</button>
  </form>
</div>
<div class="card">
  <h2>Records in RDS</h2>
  <?php if ($result->num_rows === 0): ?>
    <p class="empty">No records yet. Use the form above to add one.</p>
  <?php else: ?>
    <table>
      <tr><th>ID</th><th>Name</th><th>Address</th><th>Submitted At</th><th>Action</th></tr>
      <?php while ($row = $result->fetch_assoc()): ?>
      <tr>
        <td><?= htmlspecialchars($row['id']) ?></td>
        <td><?= htmlspecialchars($row['name']) ?></td>
        <td><?= htmlspecialchars($row['address']) ?></td>
        <td><span class="tag"><?= htmlspecialchars($row['created_at']) ?></span></td>
        <td>
          <form method="POST" onsubmit="return confirm('Delete this record?')">
            <input type="hidden" name="action" value="delete">
            <input type="hidden" name="id" value="<?= (int)$row['id'] ?>">
            <button type="submit" class="btn-delete">Delete</button>
          </form>
        </td>
      </tr>
      <?php endwhile; ?>
    </table>
  <?php endif; ?>
</div>
<?php $conn->close(); ?>
</body>
</html>
WEBEOF

rm -f /var/www/html/index.html
echo "UserData completed successfully."
